    Question(categoryId = 7, questionText = "Was ist 'Tail Latency' (P99/P999) und warum ist es fuer Microservice-Architekturen kritischer als der Durchschnitt?", answerA = "Tail Latency beschreibt die maximale Latenz des schlechtesten Requests — bei Microservices relevant wegen Fan-Out-Anfragen", answerB = "Tail Latency (P99 = 99. Perzentil) beschreibt die Latenz des langsamsten 1% der Requests; bei verteilten Fan-Out-Anfragen zu N Services multipliziert sich Tail-Latenz: Der Gesamtrequest leidet unter dem langsamsten Teilrequest", answerC = "Tail Latency ist ein Netzwerk-Phaenomen das nur bei UDP auftritt", answerD = "Tail Latency bezieht sich auf die Wartezeit im Kernel-Scheduler und ist direkt durch CPU-Affinitaet loesbar", correctAnswer = 1, explanation = "Jeffrey Dean (Google) beschrieb: Bei einem Fan-Out zu 100 Services mit je P99=1ms ist die Wahrscheinlichkeit fast 100%, dass mindestens ein Service langsam ist. 'Hedged Requests' (gleichzeitige Duplikat-Anfragen) sind eine Loesungsstrategie.", difficulty = 4, funFact = "Amazons One-Click-Bestellknopf loest hunderte Microservice-Aufrufe aus. Jede ms Tail-Latenz kostet Amazon messbar Conversion Rate."),
