    Question(categoryId = 7, questionText = "Was ist Content Delivery Network (CDN) Cache-Invalidierung und welche zwei grundlegenden Strategien loesen das Problem?", answerA = "CDN-Invalidierung betrifft nur DNS-Eintraege die nach TTL-Ablauf aktualisiert werden", answerB = "CDN-Invalidierung ist das Problem dass CDN-Knoten inkonsistente Inhalte zeigen und wird durch Anycast-Routing geloest", answerC = "CDN-Cache-Invalidierung ist das gezielte Loeschen von gecachten Dateien durch TTL-basiertes Ablaufen allein", answerD = "CDN-Invalidierung des alten Inhalts nach Deploys wird durch Cache-Busting (eindeutige Dateinamen mit Hash, z.B. main.a3f4c2.js) oder explizites Purgen ueber CDN-API geloest; Cache-Busting ist robuster, Purgen ist sofortiger", correctAnswer = 3, explanation = "Cache-Busting (Fingerprinting) ist die robustere Methode: Neue Dateinamen bedeuten, dass jede neue Version automatisch gecacht wird. Explizites Purgen ist sofort aber propagiert langsam durch hunderte PoPs.", difficulty = 4, funFact = "Cloudflare hat ueber 300 Points-of-Presence weltweit. Eine Cache-Purge-API-Anfrage wird an alle 300+ PoPs propagiert — das dauert typisch unter 150ms weltweit durch Anycast-Routing."),
